// // This module computes the logical OR of three input signals (A, B, C) and outputs the result on G.
module top_module(clk, A, B, C, G);input clk;
    input A, B, C;
    output G;

    reg G_reg;

    always @(posedge clk) begin
        G_reg <= A & B & C;
    end

    assign G = G_reg;
endmodule
